package com.company.snackledger.kiosk.api;import com.company.snackledger.kiosk.api.Dto.*;import com.company.snackledger.kiosk.config.KioskConfig;import com.fasterxml.jackson.core.type.TypeReference;import com.fasterxml.jackson.databind.*;import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;import java.net.*;import java.net.http.*;import java.util.*;public class KioskApiClient{private final KioskConfig config;private final HttpClient http;private final ObjectMapper json=new ObjectMapper().registerModule(new JavaTimeModule());public KioskApiClient(KioskConfig c){config=c;http=HttpClient.newBuilder().connectTimeout(c.connectTimeout()).build();}public Health health()throws Exception{return get("/api/v1/kiosk/health",Health.class);}public UserDto badge(String b)throws Exception{return get("/api/v1/kiosk/users/badge/"+URLEncoder.encode(b,java.nio.charset.StandardCharsets.UTF_8),UserDto.class);}public List<UserDto> users(String q)throws Exception{return getList("/api/v1/kiosk/users/search?query="+URLEncoder.encode(q,java.nio.charset.StandardCharsets.UTF_8),new TypeReference<>(){});}public ItemDto barcode(String b)throws Exception{return get("/api/v1/kiosk/items/barcode/"+URLEncoder.encode(b,java.nio.charset.StandardCharsets.UTF_8),ItemDto.class);}public List<ItemDto> items(String q)throws Exception{return getList("/api/v1/kiosk/items/search?query="+URLEncoder.encode(q,java.nio.charset.StandardCharsets.UTF_8),new TypeReference<>(){});}public PurchaseResponse purchase(PurchaseRequest r)throws Exception{return send("/api/v1/kiosk/purchases","POST",json.writeValueAsString(r),PurchaseResponse.class);}private <T>T get(String path,Class<T> type)throws Exception{return send(path,"GET",null,type);}private <T>T getList(String path,TypeReference<T> type)throws Exception{var res=request(path,"GET",null);return json.readValue(res.body(),type);}private <T>T send(String path,String method,String body,Class<T> type)throws Exception{var res=request(path,method,body);return json.readValue(res.body(),type);}private HttpResponse<String> request(String path,String method,String body)throws Exception{var b=HttpRequest.newBuilder(URI.create(config.serverUrl()+path)).timeout(config.requestTimeout()).header("X-Kiosk-Id",config.kioskId()).header("X-Kiosk-Api-Key",config.apiKey()).header("Content-Type","application/json");if("POST".equals(method))b.POST(HttpRequest.BodyPublishers.ofString(body));else b.GET();var res=http.send(b.build(),HttpResponse.BodyHandlers.ofString());if(res.statusCode()/100!=2)throw new KioskApiException(res.statusCode(),res.body());return res;}public static class KioskApiException extends RuntimeException{public final int status;public KioskApiException(int s,String m){super(m);status=s;}}}
